// MDDI 演讲稿全文与翻译。
//
// 与 video-transcripts / debate-transcripts 同构：
//   paragraphs   = 默认 locale (zh) 段落
//   paragraphsEn = 原文（英文，从 mddi.gov.sg 抓取）
// keyed by speechId，速记取自 MDDI URL 末段 slug
// (https://www.mddi.gov.sg/newsroom/<slug>/ → slug)。

import type { MddiSpeech } from './voices';

export interface SpeechTranscript {
  speechId: string;
  sourceUrl: string;
  sourceLanguage: 'en';
  fetchedAt: string;
  source: 'mddi-newsroom' | 'manual' | 'unavailable';
  /** Default-locale paragraphs (zh translation). */
  paragraphs: string[];
  /** Original speech paragraphs (English). */
  paragraphsEn: string[];
  /** Optional 3-5 sentence pull-quote / takeaway, surfaced above the fold. */
  tldr?: string[];
  tldrEn?: string[];
  translatedAt?: string;
  translationSource?: 'claude' | 'manual' | 'source';
  translationModel?: string;
  error?: string;
}

/** Derive the canonical speech id from an MDDI newsroom URL. */
export function speechIdFromUrl(url: string): string {
  const m = url.match(/\/newsroom\/([^/?#]+)/);
  return m ? m[1] : url.replace(/[^a-z0-9-]/gi, '-');
}

export function speechId(speech: Pick<MddiSpeech, 'url'>): string {
  return speechIdFromUrl(speech.url);
}

